import { scaleQuantize } from 'd3-scale';

import {
  ColorPalette,
  isCustomColorPalette,
  type CustomColorPalette,
} from '../types/color-palette.js';
import { colorPaletteMap } from '../types/color-palettes-definitions.js';

/**
 * Builds a quantized scale using a color palette for a given range.
 *
 * @internal
 *
 * @param min - The minimum value of the domain.
 * @param max - The maximum value of the domain.
 * @param colorPalette - The color palette to use for the scale. This can be a predefined color palette or a custom one.
 * @returns - A quantized scale with the specified domain and color palette.
 */
export const buildQuantizeScaleFromColorPalette = (
  min: number,
  max: number,
  colorPalette: ColorPalette | CustomColorPalette,
) => {
  let colors: string[];

  if (isCustomColorPalette(colorPalette)) {
    if (Array.isArray(colorPalette)) {
      colors = colorPalette;
    } else {
      colors = Object.values(colorPalette);
    }
  } else {
    colors = Object.entries(colorPaletteMap[colorPalette])
      .map(([_, color]: [string, { Default: string }]) => color.Default)
      // Color palettes mappings starts from the darkest color
      .reverse();
  }

  return scaleQuantize<string>([min, max], colors);
};
